namespace ShipmentTracker.Client.Models;

public class ShipmentDto
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public string Status { get; set; } = string.Empty;
    public DateTime ShippedDate { get; set; }
    public DateTime EstimatedDelivery { get; set; }
    public DateTime? ActualDelivery { get; set; }
    public string RecipientName { get; set; } = string.Empty;
    public string Notes { get; set; } = string.Empty;
}

using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public interface IShipmentService
{
    Task<List<ShipmentDto>> GetShipmentsAsync(string? statusFilter = null);
    Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task<ShipmentDto?> GetShipmentByIdAsync(int id);
    Task<ShipmentDto> CreateShipmentAsync(ShipmentDto shipment);
    Task UpdateShipmentStatusAsync(int id, string status);
}

using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService : IShipmentService
{
    private readonly HttpClient _http;

    public ShipmentHttpService(HttpClient http)
    {
        _http = http;
    }

    public async Task<List<ShipmentDto>> GetShipmentsAsync(string? statusFilter = null)
    {
        var url = "/api/shipments";
        if (!string.IsNullOrEmpty(statusFilter))
            url += $"?status={Uri.EscapeDataString(statusFilter)}";

        return await _http.GetFromJsonAsync<List<ShipmentDto>>(url) ?? new();
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var response = await _http.GetAsync($"/api/shipments/track/{Uri.EscapeDataString(trackingNumber)}");
        if (!response.IsSuccessStatusCode)
            return null;
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }

    public async Task<ShipmentDto?> GetShipmentByIdAsync(int id)
    {
        var response = await _http.GetAsync($"/api/shipments/{id}");
        if (!response.IsSuccessStatusCode)
            return null;
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }

    public async Task<ShipmentDto> CreateShipmentAsync(ShipmentDto shipment)
    {
        var response = await _http.PostAsJsonAsync("/api/shipments", shipment);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<ShipmentDto>() ?? shipment;
    }

    public async Task UpdateShipmentStatusAsync(int id, string status)
    {
        var response = await _http.PutAsJsonAsync($"/api/shipments/{id}/status", status);
        response.EnsureSuccessStatusCode();
    }
}

namespace ShipmentTracker.Data;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public string Status { get; set; } = string.Empty;
    public DateTime ShippedDate { get; set; }
    public DateTime EstimatedDelivery { get; set; }
    public DateTime? ActualDelivery { get; set; }
    public string RecipientName { get; set; } = string.Empty;
    public string Notes { get; set; } = string.Empty;
}

using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService : IShipmentService
{
    private readonly ApplicationDbContext _db;

    public ShipmentServerService(ApplicationDbContext db)
    {
        _db = db;
    }

    public async Task<List<ShipmentDto>> GetShipmentsAsync(string? statusFilter = null)
    {
        var query = _db.Shipments.AsQueryable();
        if (!string.IsNullOrEmpty(statusFilter))
            query = query.Where(s => s.Status == statusFilter);

        return await query.Select(s => MapToDto(s)).ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var entity = await _db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return entity is null ? null : MapToDto(entity);
    }

    public async Task<ShipmentDto?> GetShipmentByIdAsync(int id)
    {
        var entity = await _db.Shipments.FindAsync(id);
        return entity is null ? null : MapToDto(entity);
    }

    public async Task<ShipmentDto> CreateShipmentAsync(ShipmentDto shipment)
    {
        var entity = new Shipment
        {
            TrackingNumber = shipment.TrackingNumber,
            Origin = shipment.Origin,
            Destination = shipment.Destination,
            Status = shipment.Status,
            ShippedDate = shipment.ShippedDate,
            EstimatedDelivery = shipment.EstimatedDelivery,
            ActualDelivery = shipment.ActualDelivery,
            RecipientName = shipment.RecipientName,
            Notes = shipment.Notes
        };
        _db.Shipments.Add(entity);
        await _db.SaveChangesAsync();
        return MapToDto(entity);
    }

    public async Task UpdateShipmentStatusAsync(int id, string status)
    {
        var entity = await _db.Shipments.FindAsync(id);
        if (entity is not null)
        {
            entity.Status = status;
            if (status == "Delivered")
                entity.ActualDelivery = DateTime.UtcNow;
            await _db.SaveChangesAsync();
        }
    }

    private static ShipmentDto MapToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = s.Status,
        ShippedDate = s.ShippedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        ActualDelivery = s.ActualDelivery,
        RecipientName = s.RecipientName,
        Notes = s.Notes
    };
}

