@page "/track"
@page "/track/{TrackingNumber}"

@inject IShipmentService ShipmentService
@inject NavigationManager NavigationManager

<PageTitle>Track Shipment</PageTitle>

<h1>Track Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number"
                   @bind="searchTrackingNumber" @onkeyup="HandleKeyUp" />
            <button class="btn btn-primary" @onclick="Search">Track</button>
        </div>
    </div>
</div>

@if (loading)
{
    <p><em>Loading...</em></p>
}
else if (searched && shipment is null)
{
    <div class="alert alert-warning">
        No shipment found for tracking number <strong>@TrackingNumber</strong>.
    </div>
}
else if (shipment is not null)
{
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@shipment.TrackingNumber</strong>
            <span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <p><strong>Origin:</strong> @shipment.Origin</p>
                    <p><strong>Destination:</strong> @shipment.Destination</p>
                    <p><strong>Recipient:</strong> @shipment.RecipientName</p>
                </div>
                <div class="col-md-6">
                    <p><strong>Shipped Date:</strong> @shipment.ShippedDate.ToShortDateString()</p>
                    <p><strong>Estimated Delivery:</strong> @shipment.EstimatedDelivery.ToShortDateString()</p>
                    <p><strong>Actual Delivery:</strong> @(shipment.ActualDelivery?.ToShortDateString() ?? "N/A")</p>
                </div>
            </div>
            @if (!string.IsNullOrEmpty(shipment.Notes))
            {
                <p><strong>Notes:</strong> @shipment.Notes</p>
            }
        </div>
    </div>
}

<div class="mt-3">
    <button class="btn btn-outline-secondary" @onclick="TrackAnother">Track Another</button>
</div>

@code {
    [Parameter]
    public string? TrackingNumber { get; set; }

    private string searchTrackingNumber = string.Empty;
    private ShipmentDto? shipment;
    private bool loading;
    private bool searched;

    protected override async Task OnParametersSetAsync()
    {
        if (!string.IsNullOrWhiteSpace(TrackingNumber))
        {
            searchTrackingNumber = TrackingNumber;
            await LoadShipment();
        }
    }

    private async Task LoadShipment()
    {
        loading = true;
        searched = true;
        try
        {
            shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(TrackingNumber!);
        }
        finally
        {
            loading = false;
        }
    }

    private void Search()
    {
        if (!string.IsNullOrWhiteSpace(searchTrackingNumber))
        {
            NavigationManager.NavigateTo($"/track/{Uri.EscapeDataString(searchTrackingNumber.Trim())}");
        }
    }

    private void HandleKeyUp(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            Search();
    }

    private void TrackAnother()
    {
        shipment = null;
        searched = false;
        searchTrackingNumber = string.Empty;
        TrackingNumber = null;
        NavigationManager.NavigateTo("/track");
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Pending" => "bg-warning text-dark",
        "InTransit" => "bg-info text-dark",
        "Delivered" => "bg-success",
        "Delayed" => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/shipments"
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]

@inject IShipmentService ShipmentService

<PageTitle>Shipments</PageTitle>

<h1>Shipments</h1>

<div class="row mb-3">
    <div class="col-md-3">
        <select class="form-select" @onchange="OnFilterChanged">
            <option value="">All Statuses</option>
            <option value="Pending">Pending</option>
            <option value="InTransit">InTransit</option>
            <option value="Delivered">Delivered</option>
            <option value="Delayed">Delayed</option>
        </select>
    </div>
    <div class="col-md-3">
        <button class="btn btn-primary" @onclick="ToggleNewForm">
            @(showNewForm ? "Cancel" : "New Shipment")
        </button>
    </div>
</div>

@if (showNewForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title">Create New Shipment</h5>
            <div class="row g-3">
                <div class="col-md-4">
                    <label class="form-label">Tracking Number</label>
                    <input class="form-control" @bind="newShipment.TrackingNumber" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Origin</label>
                    <input class="form-control" @bind="newShipment.Origin" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Destination</label>
                    <input class="form-control" @bind="newShipment.Destination" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Recipient Name</label>
                    <input class="form-control" @bind="newShipment.RecipientName" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Shipped Date</label>
                    <input type="date" class="form-control" @bind="newShipment.ShippedDate" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Estimated Delivery</label>
                    <input type="date" class="form-control" @bind="newShipment.EstimatedDelivery" />
                </div>
                <div class="col-md-8">
                    <label class="form-label">Notes</label>
                    <input class="form-control" @bind="newShipment.Notes" />
                </div>
                <div class="col-md-4 d-flex align-items-end">
                    <button class="btn btn-success" @onclick="CreateShipment">Create</button>
                </div>
            </div>
        </div>
    </div>
}

@if (loading)
{
    <p><em>Loading...</em></p>
}
else if (shipments is not null)
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Shipped</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var s in shipments)
            {
                <tr>
                    <td>@s.TrackingNumber</td>
                    <td>@s.Origin</td>
                    <td>@s.Destination</td>
                    <td><span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span></td>
                    <td>@s.ShippedDate.ToShortDateString()</td>
                    <td>@s.EstimatedDelivery.ToShortDateString()</td>
                    <td>
                        <select class="form-select form-select-sm" style="width:auto;display:inline-block;"
                                @onchange="e => UpdateStatus(s.Id, e)">
                            <option value="" disabled selected>Update Status</option>
                            <option value="Pending">Pending</option>
                            <option value="InTransit">InTransit</option>
                            <option value="Delivered">Delivered</option>
                            <option value="Delayed">Delayed</option>
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<ShipmentDto>? shipments;
    private bool loading = true;
    private string? currentFilter;
    private bool showNewForm;
    private ShipmentDto newShipment = new() { Status = "Pending", ShippedDate = DateTime.Today, EstimatedDelivery = DateTime.Today.AddDays(5) };

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        loading = true;
        shipments = await ShipmentService.GetShipmentsAsync(currentFilter);
        loading = false;
    }

    private async Task OnFilterChanged(ChangeEventArgs e)
    {
        currentFilter = e.Value?.ToString();
        if (string.IsNullOrEmpty(currentFilter))
            currentFilter = null;
        await LoadShipments();
    }

    private async Task UpdateStatus(int id, ChangeEventArgs e)
    {
        var status = e.Value?.ToString();
        if (!string.IsNullOrEmpty(status))
        {
            await ShipmentService.UpdateShipmentStatusAsync(id, status);
            await LoadShipments();
        }
    }

    private void ToggleNewForm()
    {
        showNewForm = !showNewForm;
    }

    private async Task CreateShipment()
    {
        await ShipmentService.CreateShipmentAsync(newShipment);
        newShipment = new() { Status = "Pending", ShippedDate = DateTime.Today, EstimatedDelivery = DateTime.Today.AddDays(5) };
        showNewForm = false;
        await LoadShipments();
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Pending" => "bg-warning text-dark",
        "InTransit" => "bg-info text-dark",
        "Delivered" => "bg-success",
        "Delayed" => "bg-danger",
        _ => "bg-secondary"
    };
}

